import{_ as e,o as t,c as a,ai as _}from"./chunks/framework.B1-4-q7d.js";const f=JSON.parse('{"title":"“指间”管农田　“屏上”治乡村——福建深入推进数智赋能乡村振兴观察2026-04-21","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"“指间”管农田　“屏上”治乡村——福建深入推进数智赋能乡村振兴观察2026-04-21","date":"2026-04-21T00:00:00.000Z","source":"农业农村部市场与信息化司","category":"policies","link":"https://scs.moa.gov.cn/gzdt/202604/t20260421_6483454.htm","summary":"农民日报全媒体记者　高文　郭诗瑀　蔡茂楷\\n福建省莆田市涵江区大洋城乡融合农场曾经是荒地，如今几百亩智慧大棚林立，蓝莓挂满枝头，一片生机盎然。\\n武夷山市兴田镇南源岭村服务中心的智慧大屏上，实时显现村里角角落落，让乡村治理“耳聪目明”。\\n厦门市同安区大同街道田洋村村委会主任陈水让拍摄村务村情短视频，提升乡村知名度，吸引很多游客慕名而来。\\n...\\n","contentHash":"85f59c4209bc517c563c01697a33ed35","tags":["智慧农业","政策法规"]},"headers":[],"relativePath":"policies/2026-04-21-指间-管农田-屏上-治乡村-福建深入推进数智赋能乡村振兴观察.md","filePath":"policies/2026-04-21-指间-管农田-屏上-治乡村-福建深入推进数智赋能乡村振兴观察.md"}'),s={name:"policies/2026-04-21-指间-管农田-屏上-治乡村-福建深入推进数智赋能乡村振兴观察.md"};function r(o,p,n,c,l,i){return t(),a("div",null,[...p[0]||(p[0]=[_('<h1 id="指间-管农田-屏上-治乡村——福建深入推进数智赋能乡村振兴观察2026-04-21" tabindex="-1">“指间”管农田　“屏上”治乡村——福建深入推进数智赋能乡村振兴观察2026-04-21 <a class="header-anchor" href="#指间-管农田-屏上-治乡村——福建深入推进数智赋能乡村振兴观察2026-04-21" aria-label="Permalink to &quot;“指间”管农田　“屏上”治乡村——福建深入推进数智赋能乡村振兴观察2026-04-21&quot;">​</a></h1><blockquote><p>来源: <a href="https://scs.moa.gov.cn/gzdt/202604/t20260421_6483454.htm" target="_blank" rel="noreferrer">农业农村部市场与信息化司</a><br> 日期: 2026-04-21 摘要: 农民日报全媒体记者　高文　郭诗瑀　蔡茂楷 福建省莆田市涵江区大洋城乡融合农场曾经是荒地，如今几百亩智慧大棚林立，蓝莓挂满枝头，一片生机盎然。 武夷山市兴田镇南源岭村服务中心的智慧大屏上，实时显现村里角角落落，让乡村治理“耳聪目明”。 厦门市同安区大同街道田洋村村委会主任陈水让拍摄村务村情短视频，提升乡村知名度，吸引很多游客慕名而来。 ...</p></blockquote><p>福建省莆田市涵江区大洋城乡融合农场曾经是荒地，如今几百亩智慧大棚林立，蓝莓挂满枝头，一片生机盎然。</p><p>武夷山市兴田镇南源岭村服务中心的智慧大屏上，实时显现村里角角落落，让乡村治理“耳聪目明”。</p><p>厦门市同安区大同街道田洋村村委会主任陈水让拍摄村务村情短视频，提升乡村知名度，吸引很多游客慕名而来。</p><p>在地头，在村里，在山海相依间，一场场数字技术与农业农村深度融合的革命正在发生。作为数字中国建设的孕育地和实践地，近年来，福建扎实推进智慧农业建设，以数智赋能乡村振兴。“十四五”期间，福建省建设国家级数字农业创新应用基地4个、省级数字农业创新应用基地62个、省级农业物联网应用基地205个，驱动农业生产方式、农业经营方式、乡村治理方式深刻变革，为全国农业农村现代化建设提供宝贵的“福建经验”。</p><p>福建“八山一水一分田”，人均耕地面积有限，传统农业受地形、气候等自然条件影响较大，规模化、标准化发展面临诸多制约。</p><p>如何破局？福建抓住信息化变革的时代机遇，大力发展智慧农业，以优势特色产业为重点，积极推广应用农业物联网、大数据、5G、人工智能等新技术新装备，加快产业数字化、数字产业化，为农业农村数字化发展开辟出一条可行路径。</p><p>在此进程中，数据是农业农村数字化的基础，福建着力构建“农业云131”一体化平台，打造省级农业大数据中心，汇聚农业领域不同主体和环节的数据，整合粮食生产、畜禽养殖、农产品质量安全等24个业务系统，打通部、省、市、县四级数据互联互通渠道，打破“数据孤岛”，筑牢农业农村高质量发展数字底座，为农业生产调度、政策制定提供了精准的数据支撑。</p><p>在畅通数据渠道的基础上，福建持续推动数据落地应用。一块地是否撂荒、一处村集体资产是否闲置、一个特色农业产业发展情况如何，这些需要动态监测的信息往往很难被及时捕捉，福建通过数据汇聚、应用、共享，将这些关乎乡村发展的“家底”分门别类建立动态数字档案，让分散的资源可统筹调度、复杂的产业可透视明晰、广袤的乡村可智慧治理，为科学决策提供了最坚实的依据。</p><p>为进一步搭建起农业农村现代化发展的“四梁八柱”，福建提出将打造“1+3+N”数智农业体系——着力完善省级农业大数据中心；推进绘制农业用地、农业产业、乡村发展3个现代农业农村运行“一张图”；大力推广智慧粮田、智慧茶园、智慧果园、智慧畜牧、智慧菇房、智慧种业等N个智慧农业应用场景。未来，以数据底座为支撑，3个“一张图”统筹全局，N个应用场景横向铺展，一个数据驱动、协同高效、可持续演进的数字乡村立体生态正逐渐清晰。</p><p>智慧农业能否从试点走向普及、实现真正落地，直接关系到农业现代化和乡村振兴战略的成效。福建坚持“成熟一个、推广一个”思路，聚焦茶叶、水果、食用菌、畜禽等特色产业，以数字技术推动农业现代化提质增效，让“靠山吃山”有了新路径，让“寸土寸金”发挥出最大效益。</p><p>以茶产业为例，从种质资源保护到加工技艺传承、品牌孵化、市场拓展，福建正推进茶叶全产业链数字化转型。</p><p>惊蛰过后，武夷山春山吐翠，茶芽飘香。走进瑞泉茶产业有限公司，茶山遍布物联网传感器，可实时监测土壤情况、空气湿度、光照度等关键指标，改变了过去“靠天吃饭、凭经验管茶”的模式。“以前巡山要走一整天山路，现在打开手机就能查看整片茶园的情况，还能收到病虫害预警。”该企业相关负责人邓勇兴介绍。</p><p>在安溪县虎邱镇，建成全国首座“乌龙茶智能工厂”，通过AI、数字孪生技术攻克做青、包揉工艺难题，实现萎凋、杀青等全流程自动化控制，实现日产10吨毛茶、年产3000吨以上的生产能力，效率相当于传统加工厂的10倍。</p><p>农业生产品类多、差异大，发展智慧农业面临单个场景设备价格和运维费用普遍偏高、有设备需求但找不到靠谱厂商等问题。为了让不同区域、不同产业都能找到可借鉴范本，去年，福建梳理农业农村领域数字化赋能的整体供给能力与服务资源，发布了《福建省农业农村领域数字化赋能提供商清单（第一批）》和12个福建智慧农业典型案例。</p><p>福清市光阳蛋业就是典型案例之一。走进渔溪养殖场，全能蛋鸡饲养员“木鸡郎6”正依靠四轮驱动行走在现代化十足的鸡舍内，只见一个通体银灰色、身高约3米的机器人，正以摄像头和传感装置“眼观六路耳听八方”，通过人工智能深度学习技术识别家禽体态特征，可逐笼监测蛋鸡的生理状态、产蛋情况、饲料状态、水线状态，弱鸡及绝产鸡识别准确率达90%。</p><p>以“点”为突破，将“点”连成“线”、织成“面”，形成可复制、可推广的智慧农业模式，福建走出了一条“靠科技提效、靠智慧增收”的农业高质量发展之路。</p><p>作为数字中国建设的先行省份，“数字福建”建设已走过多年历程，数字技术不仅深刻改变了城市发展格局，更逐步向乡村延伸，通过工业反哺农业，发展农村电商，推动数字经济与乡村产业深度融合。</p><p>工业反哺农业，核心是将工业领域的数字技术、管理经验、市场资源，转化为农业发展的动能，推动农业从“生产导向”向“市场导向”转型，从“粗放经营”向“精细管理”升级。</p><p>如何借助雄厚的工业基础带动农村电商发展？去年9月，莆田市涵江区高新区上线了“高新甄选”平台，整合上线本地20余家企业的200多种深加工食品、日化产品，作为政府企事业单位内购平台，通过“次日达”配送模式，半年实现营收超过100万元。</p><p>“靠个别村单打独斗很难贯通产加销供应链，这是制约农村电商发展的瓶颈之一。”高新区相关负责人告诉记者。依靠当地完整的供应链体系，高新区发展订单农业，以市场需求为导向引导农户调整生产规模和标准，同时，推动小作坊标准化升级，开发枇杷冻干等深加工产品，提升农产品附加值。</p><p>而在漳州市漳浦县官浔镇溪坂村，村民自己当起了主播。“这盆三角梅有人喜欢吗？只要88元，喜光照好养护，再不拍就没了……”走进一处三角梅种植大棚，花团锦簇间，一位村民正对着手机镜头直播，下单后当天便发往全国各地。</p><p>“我们村是全省最大的花卉生产出口基地及集散中心，97%的村民从事花卉种植与经营，花木营销年收入达14.5亿元。”溪坂村村委会主任翁国兴告诉记者，为应对传统花木市场饱和、销量走低的困境，村里探索发展“庭院景观+电商”的新模式，把直播间搬进大棚，将经营重心从传统大苗木转向盆景等“小而美”的庭院经济，通过“园艺+电商+场景+服务”的深度融合，为溪坂村的发展注入新活力。</p><p>近年来，福建坚持实施“互联网+”农产品出村进城工程，连续3年举办中国电商主播大赛，组建福建电商助农联盟，培育“乡愁沈丹”“小田姑娘”等一批乡村振兴领域网络达人。2025年，福建省农村网络零售额达3054.1亿元，农产品网络零售额达649.5亿元。农村电商、直播等数字经济新业态等成为农民增收的新引擎，“数字福建”的基因逐步在乡村沃土里生根发芽、开花结果。</p><p>数字乡村并非简单地将新技术引入农村，而是要服务于农业农村发展的整体目标，要把“农民是否受益”作为衡量数字乡村成效的第一标准。福建坚持小切口、小投入，推广“十个小微”数字乡村应用场景，将数字技术融入乡村治理、民生服务、环境整治等各个方面，构建起“共建共治共享”的乡村治理新格局。</p><p>民生服务方面，通过“村事码上办”等应用场景，让村民足不出户就能办理事务、享受服务。在福州市罗源县中房镇下湖村，村民通过“智慧下湖”小程序，有事随手一拍，即可在手机上上报问题、提诉求，再由村党支部转交村网格员接单办理，效率大幅提升。这些看似简单的小功能，却能将传统的群众诉求、政务服务，通过重构数字化响应机制，简化问题上报流程，建立“群众点单、网格接单”的线上闭环管理模式，缩短事件处置响应与解决时间，为群众提供了极大便利，有效提升乡村治理精细化水平。</p><p>乡村建设方面，数字技术成为“好帮手”，让乡村更干净、更美丽。在漳州市长泰区石横村，村民看到垃圾乱倒、路灯损坏问题，拍张照片上传至“i石横”平台，网格长和网格员就能精准定位、及时处理。“随手拍”功能让村民成为乡村治理的“千里眼”“顺风耳”。</p><p>农村养老方面，“云守护”为守护留守老人健康助力。在泉州市德化县杨梅乡，20位农村老人戴上了智能手环，实时监测身体健康状况，94户独居老人安装了语音监控、出入门检测设备及一键应急按钮，家属可通过“云上杨梅”小程序随时查看，守护空巢老人平安。</p><p>福建的实践表明，只有当数字技术真正走进生活，乡村治理的“最后一米”才能真正触手可及，给老百姓带来实实在在的改变。</p><p>行之力则知愈进，知之深则行愈达。世纪之交，时任福建省省长的习近平同志作出建设“数字福建”的战略决策，开启了中国数字化建设的先声。站在“十四五”收官、“十五五”开局的关键节点，总结福建推进农业农村数智化进程的实践经验，为全国其他地区提供了可借鉴的参考。</p><p>顶层设计与基层探索相结合。福建将持续以“1+3+N”数智农业体系为引领，着力完善省级农业大数据中心，推进绘制3个现代农业农村运行“一张图”，大力推广N个智慧农业应用场景，并通过“十个小微”等小切口，让各地因地制宜、各美其美，通过“自上而下”与“自下而上”的结合，确保数字赋能有方向、有动力、有活力。</p><p>试点先行与稳步推进相衔接。福建定期发布智慧农业典型案例，组织制修订一批数智农业共性关键标准与通用技术规范，做好产业链上下游、成套装备的标准衔接。这种稳扎稳打、次第推进的做法，更加行稳致远。</p><p>人才培养与长效机制相支撑。数字赋能乡村，关键在人。福建通过产学研融合，鼓励高等院校、科研院所与智慧农业企业合作，培养应用型、创新型和复合型人才。同时，结合农村实用人才带头人培训、高素质农民培育、农民手机应用技能培训等项目，加大智慧农业人才培养力度，为乡村振兴注入源源不断的“数字血液”。</p><p>勇立潮头，八闽大地踔厉向“新”。从“数字福建”到“数字乡村”，福建正以敢为人先的精神，在数智赋能乡村振兴的道路上奋力前行。</p><p><a href="https://scs.moa.gov.cn/gzdt/202604/t20260421_6483454.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',36)])])}const m=e(s,[["render",r]]);export{f as __pageData,m as default};
